}\n\n/* Divi section-level overrides */\n.et_pb_section:has(.lib-inner) {\n  background: #ffffff !important; padding: 0 !important; min-height: auto !important;\n  margin-top: 0 !important; margin-bottom: 0 !important; text-align: start !important;\n}\n.lib-section {\n  padding: 100px 24px !important; position: relative !important; overflow: hidden !important;\n}\n.lib-section canvas {\n  position: absolute !important; top: 0 !important; left: 0 !important;\n  width: 100% !important; height: 100% !important; pointer-events: none !important; z-index: 1 !important;\n}\n.et_pb_section:has(.lib-inner) .et_pb_row {\n  max-width: 100% !important; width: 100% !important; padding: 0 !important; margin: 0 auto !important;\n}\n.et_pb_section:has(.lib-inner) .et_pb_column { padding: 0 !important; }\n.et_pb_section .lib-inner {\n  max-width: 1200px !important; margin: 0 auto !important; padding: 0 24px !important;\n  -webkit-font-smoothing: auto !important;\n}\n.et_pb_section .lib-header { text-align: center !important; margin-bottom: 56px !important; }\n.et_pb_section .lib-header h2 {\n  font-family: \'Noto Sans\', sans-serif !important; font-size: 40px !important;\n  font-weight: 700 !important; color: #000864 !important; margin: 8px 0 0 !important;\n  letter-spacing: -0.02em !important; line-height: 64px !important; padding: 0 !important;\n  -webkit-font-smoothing: auto !important;\n}\n.et_pb_section .blog-hub-label {\n  font-family: \'JetBrains Mono\', monospace !important; font-size: 11px !important;\n  font-weight: 500 !important; color: #0369a1 !important; text-transform: uppercase !important;\n  letter-spacing: 0.15em !important; margin-bottom: 32px !important; display: block !important;\n  line-height: 17.6px !important; -webkit-font-smoothing: auto !important;\n}\n.et_pb_section .lib-groups {\n  display: grid !important; grid-template-columns: repeat(2, 1fr) !important; gap: 32px !important;\n}\n.et_pb_section .lib-group {\n  background: #F5F7FA !important; border-radius: 16px !important; padding: 32px !important;\n  border: 1px solid #e8eef3 !important;\n}\n.et_pb_section .lib-group-header {\n  display: flex !important; align-items: center !important; gap: 12px !important;\n  padding-bottom: 20px !important; margin-bottom: 20px !important;\n  border-bottom: 2px solid #e8eef3 !important;\n}\n.et_pb_section .lib-group-indicator {\n  width: 4px !important; height: 32px !important; border-radius: 2px !important;\n}\n.et_pb_section .lib-group-indicator--boi { background: #DC2626 !important; }\n.et_pb_section .lib-group-indicator--production { background: #00AFF0 !important; }\n.et_pb_section .lib-group-indicator--cost { background: #02D28C !important; }\n.et_pb_section .lib-group-indicator--smart { background: #644CE6 !important; }\n.et_pb_section .lib-group-indicator--industry { background: #FFD700 !important; }\n.et_pb_section .lib-group-header h3 {\n  font-family: \'Noto Sans\', sans-serif !important; font-size: 18px !important;\n  font-weight: 600 !important; color: #000864 !important; margin: 0 !important;\n  padding: 0 !important; -webkit-font-smoothing: auto !important;\n  line-height: 28.8px !important; text-align: start !important;\n}\n.et_pb_section .lib-item {\n  display: flex !important; align-items: center !important; justify-content: space-between !important;\n  padding: 14px 0 !important; border-bottom: 1px solid #e8eef3 !important;\n  text-decoration: none !important; line-height: 25.6px !important;\n  -webkit-font-smoothing: auto !important; color: #333 !important; text-align: start !important;\n}\n.et_pb_section .lib-item:last-child { border-bottom: none !important; padding-bottom: 0 !important; }\n.et_pb_section .lib-item-title {\n  font-size: 15px !important; font-weight: 500 !important; color: #333 !important;\n  flex: 1 !important; margin-right: 16px !important;\n  -webkit-font-smoothing: auto !important; line-height: 24px !important; text-align: start !important;\n}\n.et_pb_section .lib-item-meta {\n  display: flex !important; align-items: center !important; gap: 12px !important; flex-shrink: 0 !important;\n}\n.et_pb_section .lib-item-time {\n  font-size: 13px !important; color: #666 !important; white-space: nowrap !important;\n  line-height: 20.8px !important; -webkit-font-smoothing: auto !important; text-align: start !important;\n}\n.et_pb_section .lib-item-arrow {\n  font-size: 16px !important; color: #0369a1 !important; opacity: 0 !important;\n  line-height: 25.6px !important; -webkit-font-smoothing: auto !important; text-align: start !important;\n}\n.et_pb_section .dw-d-bg {\n  position: absolute !important; pointer-events: none !important; z-index: 0 !important;\n  left: -5% !important; top: -5% !important; right: auto !important; bottom: auto !important;\n  width: 30% !important; min-height: 30vh !important;\n  background-size: contain !important; background-repeat: no-repeat !important;\n  background-position: center left !important;\n  background-image: url("data:image/svg+xml;base64,") !important;\n  transform: none !important;\n}\n/* === HUB CTA (S5) === */\n/* Divi 5 section boilerplate (font-smoothing, p padding, heading resets) */\n.hubc-section{position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.hubc-section p{padding-bottom:0;line-height:1.6}\n.hubc-section h2,.hubc-section h3,.hubc-section h4{margin:0;padding:0;line-height:1.6}\n\n\n/* === HOVER STATES (auto-ported from styles.css) === */\n.hubc-btn-white:hover{transform:translateY(-2px);box-shadow:0 8px 32px rgba(0, 0, 0, 0.2)}\n.hubc-btn-outline:hover{border-color:#fff;background:rgba(255, 255, 255, 0.1)}\n/* === PSEUDO-ELEMENTS (auto-ported from styles.css) === */\n.hubc-cta::before{content:\'\';position:absolute;inset:0;background-image:url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Ccircle cx=\'30\' cy=\'30\' r=\'1.5\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");pointer-events:none}\n.hubc-cta::after{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background:radial-gradient(ellipse at 50% 50%, rgba(0, 175, 240, 0.1) 0%, transparent 60%);pointer-events:none}\n/* WARNING: HIDDEN in styles.css (display:none) — DO NOT include in builder HTML */\n/* .dw-wave-flow,\n * .dw-wave-flow--top {\n *     display: none;\n * } */\n/* REF: BASE RULES from styles.css (check against inline CSS above) */\n/* .dw-d-bg{position:absolute;right:-10%;top:50%;transform:translateY(-50%);width:60%;min-height:60vh;background:url(\'assets/digiwin-d-outline.svg\') no-repeat center right;background-size:contain;pointer-events:none;z-index:0;opacity:0.12} */\n/* .dw-d-bg--gradient{background-image:url(\'assets/digiwin-d-gradient.svg\');opacity:0.15} */\n/* .dw-d-bg--particle{background-image:url(\'assets/digiwin-d-particle.svg\');opacity:0.2} */\n/* .dw-d-bg--left{right:auto;left:-15%;background-position:center left} */\n/* .dw-d-bg--bottom{top:auto;bottom:-20%;transform:none;background-position:center bottom} */\n/* .dw-d-bg--top{top:-20%;transform:none;background-position:center top} */\n/* .dw-d-bg--center{right:auto;left:50%;transform:translate(-50%, -50%);width:80%;min-height:80vh;background-position:center center} */\n/* .dw-d-bg--corner{width:30%;min-height:30vh} */\n/* .dw-d-bg--corner-tl{right:auto;left:-5%;top:-5%;transform:none} */\n/* .dw-d-bg--corner-br{top:auto;bottom:-5%;right:-5%;transform:none} */\n/* .dw-d-bg--bold{opacity:0.22 !important} */\n/* .dw-d-bg--medium{opacity:0.14 !important} */\n/* .dw-d-bg--subtle{opacity:0.06 !important} */\n/* .dw-wave-flow--top{bottom:auto;top:0;transform:scaleY(-1)} */\n/* .blog-hub-cta{padding:120px 0;background:linear-gradient(135deg, #000432 0%, #000864 50%, #001080 100%);position:relative;overflow:hidden;text-align:center} */\n/* .blog-hub-cta-inner{max-width:700px;margin:0 auto;padding:0 24px;position:relative;z-index:1} */\n/* .blog-hub-cta h2{font-family:\'Noto Sans\', sans-serif;font-size:clamp(32px, 4vw, 44px);font-weight:700;color:#fff;margin:0 0 20px 0;line-height:1.15;letter-spacing:-0.02em} */\n/* .blog-hub-cta p{font-family:\'Noto Sans\', sans-serif;font-size:18px;color:rgba(255, 255, 255, 0.8);line-height:1.6;margin:0 0 40px 0} */\n/* .blog-hub-cta-buttons{display:flex;justify-content:center;gap:16px;flex-wrap:wrap} */\n/* .blog-hub-btn-white{background:#fff;color:#000864;padding:16px 36px;border-radius:12px;font-family:\'Noto Sans\', sans-serif;font-weight:600;font-size:16px;text-decoration:none;transition:all 0.3s ease;box-shadow:0 4px 16px rgba(0, 0, 0, 0.15)} */\n/* .blog-hub-btn-outline{background:transparent;color:#fff;padding:16px 36px;border:2px solid rgba(255, 255, 255, 0.4);border-radius:12px;font-family:\'Noto Sans\', sans-serif;font-weight:600;font-size:16px;text-decoration:none;transition:all 0.3s ease} */\n/* @media (max-width:640px){.blog-hub-cta h2{font-size:28px}.blog-hub-cta-buttons{flex-direction:column}.blog-hub-btn-white,.blog-hub-btn-outline{width:100%;text-align:center}} */\n.dw-d-bg{position:absolute;top:50%;right:auto;left:-15%;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center left;background-size:contain;transform:translateY(-50%);opacity:0.12;pointer-events:none;z-index:0}\n\n@media(prefers-reduced-motion:reduce){*{animation:none !important;transition:none !important}}\n\n/* Divi section-level overrides */\n.et_pb_section:has(.hubc-cta-inner) {\n  background: linear-gradient(135deg, #000432 0%, #000864 50%, #001080 100%) !important;\n  padding: 120px 24px !important;\n  position: relative !important; overflow: hidden !important; text-align: center !important;\n  min-height: auto !important;\n  margin-top: 0 !important; margin-bottom: 0 !important;\n}\n.et_pb_section:has(.hubc-cta-inner)::before {\n  content: \'\' !important; position: absolute !important; inset: 0 !important;\n  background-image: url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Ccircle cx=\'30\' cy=\'30\' r=\'1.5\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E") !important;\n  pointer-events: none !important;\n}\n.et_pb_section:has(.hubc-cta-inner)::after {\n  content: \'\' !important; position: absolute !important; inset: 0 !important;\n  background: radial-gradient(ellipse at 50% 50%, rgba(0,175,240,0.1) 0%, transparent 60%) !important;\n  pointer-events: none !important;\n}\n.et_pb_section:has(.hubc-cta-inner) .et_pb_row {\n  max-width: 100% !important; width: 100% !important; padding: 0 !important; margin: 0 auto !important;\n}\n.et_pb_section:has(.hubc-cta-inner) .et_pb_column { padding: 0 !important; }\n.et_pb_section .hubc-cta-inner {\n  max-width: 700px !important; margin: 0 auto !important; padding: 0 24px !important;\n  position: relative !important; z-index: 1 !important;\n  -webkit-font-smoothing: auto !important;\n}\n.et_pb_section .hubc-cta-inner h2 {\n  font-family: \'Noto Sans\', sans-serif !important; font-size: 44px !important;\n  font-weight: 700 !important; color: #fff !important; margin: 0 0 20px !important;\n  line-height: 1.15 !important; letter-spacing: -0.02em !important; padding: 0 !important;\n  -webkit-font-smoothing: auto !important;\n}\n.et_pb_section .hubc-cta-inner p {\n  font-size: 18px !important; color: rgba(255,255,255,0.8) !important;\n  line-height: 1.6 !important; margin: 0 0 40px !important; padding-bottom: 0 !important;\n  -webkit-font-smoothing: auto !important;\n}\n.et_pb_section .hubc-cta-buttons {\n  display: flex !important; justify-content: center !important; gap: 16px !important; flex-wrap: wrap !important;\n}\n.et_pb_section .hubc-btn-white {\n  background: #fff !important; color: #000864 !important;\n  padding: 16px 36px !important; border-radius: 12px !important;\n  font-family: \'Noto Sans\', sans-serif !important; font-weight: 600 !important;\n  font-size: 16px !important; text-decoration: none !important; line-height: 25.6px !important;\n  box-shadow: 0 4px 16px rgba(0,0,0,0.15) !important;\n  -webkit-font-smoothing: auto !important;\n}\n.et_pb_section .hubc-btn-outline {\n  background: transparent !important; color: #fff !important;\n  padding: 16px 36px !important; border: 2px solid rgba(255,255,255,0.4) !important;\n  border-radius: 12px !important; font-family: \'Noto Sans\', sans-serif !important;\n  font-weight: 600 !important; font-size: 16px !important; text-decoration: none !important;\n  line-height: 25.6px !important; -webkit-font-smoothing: auto !important;\n}\n.et_pb_section .dw-d-bg {\n  position: absolute !important; pointer-events: none !important; z-index: 0 !important;\n  left: -15% !important; top: 50% !important; right: auto !important;\n  width: 60% !important; min-height: 60vh !important;\n  background-size: contain !important; background-repeat: no-repeat !important;\n  background-position: center left !important;\n  background-image: url("data:image/svg+xml;base64,") !important;\n  transform: translateY(-50%) !important;\n}\n.et_pb_section .dw-wave-flow { display: none !important; }\n\n/* === THAI TYPOGRAPHY === */\n/* Font loaded via <link> in header — do NOT use @import here (invalid after rules) */\n\n/* Thai font stack for all body text */\nbody, .et_pb_section, .et_pb_code, .et_pb_code_inner {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* Thai-specific line heights (Thai script is taller — needs !important to override Divi) */\np, li, .et_pb_text_inner { line-height: 1.8 !important; }\nh1, h2, h3, h4, h5, h6 { line-height: 1.4 !important; }\n\n/* Thai label override: JetBrains Mono doesn\'t have Thai glyphs.\n   letter-spacing breaks Thai script (chars within words must stay connected).\n   text-transform:uppercase is meaningless for Thai. */\n[class*="-label"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n/* Also fix any monospace elements that might contain Thai text */\n[class*="-source"], [class*="-company"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hub Hero"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hub Hero: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"valu