\n\n                    <line x1="140" y1="180" x2="80" y2="244" stroke="#00AFF0" stroke-width="0.8" stroke-dasharray="4 4"/>\n                    <line x1="140" y1="180" x2="200" y2="266" stroke="#00AFF0" stroke-width="0.8" stroke-dasharray="4 4"/>\n                    <line x1="80" y1="276" x2="60" y2="352" stroke="#00AFF0" stroke-width="0.8" stroke-dasharray="4 4"/>\n                    <line x1="80" y1="276" x2="170" y2="368" stroke="#00AFF0" stroke-width="0.8" stroke-dasharray="4 4"/>\n                    <line x1="200" y1="294" x2="170" y2="368" stroke="#00AFF0" stroke-width="0.8" stroke-dasharray="4 4"/>\n\n                    <circle cx="140" cy="160" r="5" fill="#00AFF0" opacity="0.4"/>\n                    <circle cx="80" cy="260" r="4" fill="#00AFF0" opacity="0.3"/>\n                    <circle cx="200" cy="280" r="3" fill="#00AFF0" opacity="0.3"/>\n\n                    <circle cx="420" cy="380" r="40" stroke="#00AFF0" stroke-width="1.5"/>\n                    <line x1="448" y1="408" x2="480" y2="440" stroke="#00AFF0" stroke-width="3" stroke-linecap="round"/>\n                    <circle cx="420" cy="380" r="20" stroke="#00AFF0" stroke-width="0.8" stroke-dasharray="3 3"/>\n\n                    <circle cx="250" cy="400" r="3" fill="#00AFF0" opacity="0.3"/>\n                    <circle cx="230" cy="120" r="2" fill="#00AFF0" opacity="0.2"/>\n                    <circle cx="500" cy="320" r="2.5" fill="#00AFF0" opacity="0.25"/>\n                    <circle cx="520" cy="140" r="2" fill="#00AFF0" opacity="0.2"/>\n                    <circle cx="160" cy="100" r="2.5" fill="#00AFF0" opacity="0.2"/>\n                    <circle cx="350" cy="350" r="2" fill="#00AFF0" opacity="0.15"/>\n                    <circle cx="100" cy="140" r="1.5" fill="#00AFF0" opacity="0.2"/>\n                </svg>\n            </div>\n            <div class="hubh-hero-inner">\n                <div class="hubh-hero-badge">\n                    <span>ความรู้และข้อมูลเชิงลึก</span>\n                </div>\n                <h1>ความรู้ด้านการผลิต แบ่งปันจากประสบการณ์จริง</h1>\n                <p class="hubh-hero-subtitle">คู่มือเชิงเทคนิค ข้อมูลเชิงลึกด้านการปฏิบัติตามกฎระเบียบ และเรื่องราวการติดตั้งจริงจากพื้นที่หน้างานในประเทศไทย</p>\n                <div class="hubh-hero-stats">\n                    <div class="hubh-hero-stat">\n                        <div class="hubh-hero-stat-number">5</div>\n                        <div class="hubh-hero-stat-label">หมวดหมู่</div>\n                    </div>\n                    <div class="hubh-hero-stat">\n                        <div class="hubh-hero-stat-number">เจาะลึก</div>\n                        <div class="hubh-hero-stat-label">บทความ</div>\n                    </div>\n                    <div class="hubh-hero-stat">\n                        <div class="hubh-hero-stat-number">จริง</div>\n                        <div class="hubh-hero-stat-label">กรณีศึกษา</div>\n                    </div>\n                </div>\n            </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hub Featured"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hub Featured: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hub Featured: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="hubf-featured-inner" style="position: relative; z-index: 2;">\n                <span class="hubf-label">บทความแนะนำ</span>\n                <div class="hubf-featured-card">\n                    <div class="hubf-featured-card-image">\n\n                        <svg aria-hidden="true" viewBox="0 0 120 120">\n                            <rect x="25" y="10" width="70" height="90" rx="6" stroke-width="2"/>\n                            <line x1="40" y1="35" x2="80" y2="35" stroke-width="2"/>\n                            <line x1="40" y1="50" x2="75" y2="50" stroke-width="2"/>\n                            <line x1="40" y1="65" x2="70" y2="65" stroke-width="2"/>\n                            <path d="M60 75 L60 105 L75 95 L90 105 L90 75 Z" stroke-width="2" fill="none"/>\n                            <path d="M75 82 L72 85 L78 91" stroke-width="2" fill="none"/>\n                        </svg>\n                    </div>\n                    <div class="hubf-featured-card-content">\n                        <span class="hubf-category-badge">BOI และการปฏิบัติตามกฎระเบียบ</span>\n                        <h2>โรงงานแห่งหนึ่งประหยัดภาษีเพิ่มเติม BOI ได้ 10 ล้านบาทต่อปี ได้อย่างไร</h2>\n                        <p>เมื่อคณะกรรมการ BOI ตรวจสอบบันทึกการผลิตของ Jin Hai พบว่าส่วนต่างระหว่างวัตถุดิบนำเข้ากับปริมาณการใช้จริงทำให้เสียเงินกว่า 10 ล้านบาทต่อปี ระบบการกระทบยอดระดับใบสั่งผลิตช่วยแก้ปัญหาได้ทั้งหมด</p>\n                        <div class="hubf-featured-meta">อ่าน 8 นาที</div>\n                        <a href="/blog/boi-compliance-jin-hai/" class="hubf-featured-link">อ่านเรื่องเต็ม <span>&rarr;</span></a>\n                    </div>\n                </div>\n            </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Articles"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Articles: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Articles: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="articles-inner" style="position: relative; z-index: 2;">\n                <div class="articles-header">\n                    <span class="blog-hub-label">บทความทั้งหมด</span>\n                    <h2>เลือกอ่านตามหัวข้อ</h2>\n                </div>\n                <input type="radio" name="blogfilter" id="bf-all" checked style="position:absolute;opacity:0;pointer-events:none">\n                <input type="radio" name="blogfilter" id="bf-boi" style="position:absolute;opacity:0;pointer-events:none">\n                <input type="radio" name="blogfilter" id="bf-production" style="position:absolute;opacity:0;pointer-events:none">\n                <input type="radio" name="blogfilter" id="bf-cost" style="position:absolute;opacity:0;pointer-events:none">\n                <input type="radio" name="blogfilter" id="bf-smart" style="position:absolute;opacity:0;pointer-events:none">\n                <input type="radio" name="blogfilter" id="bf-industry" style="position:absolute;opacity:0;pointer-events:none">\n                <div class="blog-hub-filter-tabs">\n                    <label for="bf-all" class="blog-hub-filter-tab">ทั้งหมด</label>\n                    <label for="bf-boi" class="blog-hub-filter-tab">BOI และกฎระเบียบ</label>\n                    <label for="bf-production" class="blog-hub-filter-tab">การวางแผนการผลิต</label>\n                    <label for="bf-cost" class="blog-hub-filter-tab">การบริหารต้นทุน</label>\n                    <label for="bf-smart" class="blog-hub-filter-tab">Smart Factory</label>\n                    <label for="bf-industry" class="blog-hub-filter-tab">ข้อมูลเชิงลึกอุตสาหกรรม</label>\n                </div>\n\n                <div class="articles-grid">\n\n                    <a href="/blog/boi-compliance-jin-hai/" class="art-card" data-category="boi">\n                        <div class="art-card-image art-card-image--boi">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></svg>\n                        </div>\n                        <div class="art-card-body">\n                            <span class="art-category-badge badge--boi">BOI และกฎระเบียบ</span>\n                            <h3>โรงงานแห่งหนึ่งประหยัดภาษีเพิ่มเติม BOI ได้ 10 ล้านบาทต่อปี ได้อย่างไร</h3>\n                            <p class="art-card-excerpt">เมื่อคณะกรรมการ BOI ตรวจสอบบันทึกการผลิตของ Jin Hai พบว่าส่วนต่างระหว่างวัตถุดิบนำเข้ากับปริมาณการใช้จริงทำให้เสียเงินกว่า 10 ล้านบาทต่อปี</p>\n                            <div class="art-card-footer">\n                                <span class="art-read-time">อ่าน 8 นาที</span>\n                                <span class="art-read-link">อ่านบทความ <span>&rarr;</span></span>\n                            </div>\n                        </div>\n                    </a>\n\n                    <a href="/blog/lrp-vs-mrp/" class="art-card" data-category="production">\n                        <div class="art-card-image art-card-image--production">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n                        </div>\n                        <div class="art-card-body">\n                            <span class="art-category-badge badge--production">การวางแผนการผลิต</span>\n                            <h3>LRP vs MRP: ทำไมการวางแผนการผลิตของคุณใช้เวลาหลายชั่วโมงแทนที่จะเป็นนาที</h3>\n                            <p class="art-card-excerpt">โรงงานส่วนใหญ่ยังใช้ MRP แบบที่ออกแบบมาตั้งแต่ยุค 1960 LRP (การวางแผนความต้องการตาม Lot) คิดใหม่ทั้งวิธีการสำหรับการผลิตยุคใหม่</p>\n                            <div class="art-card-footer">\n                                <span class="art-read-time">อ่าน 6 นาที</span>\n                                <span class="art-read-link">อ่านบทความ <span>&rarr;</span></span>\n                            </div>\n                        </div>\n                    </a>\n\n                    <a href="/blog/co-product-cost-accounting/" class="art-card" data-category="cost">\n                        <div class="art-card-image art-card-image--cost">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><line x1="12" y1="1" x2="12" y2="23"/><path d="M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg>\n                        </div>\n                        <div class="art-card-body">\n                            <span class="art-category-badge badge--cost">การบริหารต้นทุน</span>\n                            <h3>การคิดต้นทุนผลิตภัณฑ์ร่วม: ปัญหาที่ ERP ส่วนใหญ่แก้ไม่ได้</h3>\n                            <p class="art-card-excerpt">เมื่อการผลิตหนึ่งครั้งได้ผลิตภัณฑ์ขายได้หลายตัว คุณจะจัดสรรต้นทุนอย่างแม่นยำได้อย่างไร ERP ส่วนใหญ่บังคับให้เลือกอย่างเดียว แต่ DigiWin ไม่ได้ทำแบบนั้น</p>\n                            <div class="art-card-footer">\n                                <span class="art-read-time">อ่าน 7 นาที</span>\n                                <span class="art-read-link">อ่านบทความ <span>&rarr;</span></span>\n                            </div>\n                        </div>\n                    </a>\n\n                    <a href="/blog/feature-codes/" class="art-card" data-category="production">\n                        <div class="art-card-image art-card-image--production">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><polyline points="16 18 22 12 16 6"/><polyline points="8 6 2 12 8 18"/></svg>\n                        </div>\n                        <div class="art-card-body">\n                            <span class="art-category-badge badge--production">การวางแผนการผลิต</span>\n                            <h3>Feature Codes: วิธีเปลี่ยน 27 SKU ให้เหลือ 1 ผลิตภัณฑ์</h3>\n                            <p class="art-card-excerpt">หากแคตตาล็อกสินค้าของคุณเต็มไปด้วยรุ่นที่เหมือนกัน 90% Feature Codes ช่วยจัดการความซับซ้อนโดยไม่จมอยู่กับ SKU</p>\n                            <div class="art-card-footer">\n                                <span class="art-read-time">อ่าน 5 นาที</span>\n                                <span class="art-read-link">อ่านบทความ <span>&rarr;</span></span>\n                            </div>\n                        </div>\n                    </a>\n\n                    <a href="/blog/amrp-capacity-planning/" class="art-card" data-category="production">\n                        <div class="art-card-image art-card-image--production">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M3 3v18h18"/><path d="M18.7 8l-5.1 5.2-2.8-2.7L7 14.3"/></svg>\n                        </div>\n                        <div class="art-card-body">\n                            <span class="art-category-badge badge--production">การวางแผนการผลิต</span>\n                            <h3>AMRP: ทำไมคุณไม่จำเป็นต้องมีระบบ APS แยกต่างหาก</h3>\n                            <p class="art-card-excerpt">Advanced MRP ที่มีข้อจำกัดกำลังการผลิตในตัวช่วยลดความจำเป็นในการซื้อซอฟต์แวร์ APS แยกราคาแพง ดูว่าทำงานอย่างไรภายใน ERP ของคุณ</p>\n                            <div class="art-card-footer">\n                                <span class="art-read-time">อ่าน 6 นาที</span>\n                                <span class="art-read-link">อ่านบทความ <span>&rarr;</span></span>\n                            </div>\n                        </div>\n                    </a>\n\n                    <a href="/blog/five-pain-points/" class="art-card" data-category="industry">\n                        <div class="art-card-image art-card-image--industry">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M14.7 6.3a1 1 0 0 0 0 1.4l1.6 1.6a1 1 0 0 0 1.4 0l3.77-3.77a6 6 0 0 1-7.94 7.94l-6.91 6.91a2.12 2.12 0 0 1-3-3l6.91-6.91a6 6 0 0 1 7.94-7.94l-3.76 3.76z"/></svg>\n                        </div>\n                        <div class="art-card-body">\n                            <span class="art-category-badge badge--industry">ข้อมูลเชิงลึกอุตสาหกรรม</span>\n                            <h3>5 ปัญหาสากลที่เจ้าของโรงงานไทยทุกคนต้องเผชิญ</h3>\n                            <p class="art-card-excerpt">ตั้งแต่ค่าใช้จ่ายที่ไม่คาดคิดตอนสิ้นเดือน ไปจนถึงคำถามที่ถามกันไม่รู้จบ "ออเดอร์ไปถึงไหนแล้ว?" ความท้าทาย 5 ข้อเหล่านี้เป็นสิ่งที่ผู้ผลิตไทยทุกรายต้องเจอ</p>\n                            <div class="art-card-footer">\n                                <span class="art-read-time">อ่าน 10 นาที</span>\n                                <span class="art-read-link">อ่านบทความ <span>&rarr;</span></span>\n                            </div>\n                        </div>\n                    </a>\n\n                    <a href="/blog/sap-ecc-end-of-life/" class="art-card" data-category="industry">\n                        <div class="art-card-image art-card-image--industry">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>\n                        </div>\n                        <div class="art-card-body">\n                            <span class="art-category-badge badge--industry">ข้อมูลเชิงลึกอุตสาหกรรม</span>\n                            <h3>SAP ECC สิ้นสุดการสนับสนุน 2027: สิ่งที่ผู้ผลิตไทยต้องรู้</h3>\n                            <p class="art-card-excerpt">การสนับสนุนหลักของ SAP สำหรับ ECC จะสิ้นสุดในปี 2027 สำหรับโรงงานไทย นี่สร้างทั้งความเร่งด่วนและโอกาสในการคิดใหม่เรื่องกลยุทธ์เทคโนโลยี</p>\n                            <div class="art-card-footer">\n                                <span class="art-read-time">อ่าน 7 นาที</span>\n                                <span class="art-read-link">อ่านบทความ <span>&rarr;</span></span>\n                            </div>\n                        </div>\n                    </a>\n\n                    <a href="/blog/dual-units/" class="art-card" data-category="cost">\n                        <div class="art-card-image art-card-image--cost">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z"/><polyline points="3.27 6.96 12 12.01 20.73 6.96"/><line x1="12" y1="22.08" x2="12" y2="12"/></svg>\n                        </div>\n                        <div class="art-card-body">\n                            <span class="art-category-badge badge--cost">การบริหารต้นทุน</span>\n                            <h3>หน่วยคู่: ทำไม ERP ของคุณควรแสดงทั้งกิโลกรัมและจำนวนชิ้น</h3>\n                            <p class="art-card-excerpt">ฝ่ายจัดซื้อซื้อเป็นกิโลกรัม การผลิตใช้เป็นชิ้น ฝ่ายขายส่งเป็นกล่อง ถ้า ERP ติดตามแค่หน่วยเดียว ต้องมีคนคอยแปลงหน่วยด้วยมือเสมอ</p>\n                            <div class="art-card-footer">\n                                <span class="art-read-time">อ่าน 5 นาที</span>\n                                <span class="art-read-link">อ่านบทความ <span>&rarr;</span></span>\n                            </div>\n                        </div>\n                    </a>\n\n                    <a href="/blog/shop-floor-scheduling/" class="art-card" data-category="smart">\n                        <div class="art-card-image art-card-image--smart">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><rect x="2" y="3" width="20" height="14" rx="2" ry="2"/><line x1="8" y1="21" x2="16" y2="21"/><line x1="12" y1="17" x2="12" y2="21"/></svg>\n                        </div>\n                        <div class="art-card-body">\n                            <span class="art-category-badge badge--smart">Smart Factory</span>\n                            <h3>การจัดตารางย่อยหน้างาน: เมื่อแผนเจอความเป็นจริง</h3>\n                            <p class="art-card-excerpt">ผู้วางแผนสร้างตารางหลัก แต่ที่หน้างาน เครื่องจักรเสีย วัตถุดิบมาช้า ออเดอร์ด่วนโผล่มา การจัดตารางย่อยช่วยเชื่อมช่องว่างนี้</p>\n                            <div class="art-card-footer">\n                                <span class="art-read-time">อ่าน 6 นาที</span>\n                                <span class="art-read-link">อ่านบทความ <span>&rarr;</span></span>\n                            </div>\n                        </div>\n                    </a>\n\n                    <a href="/blog/production-transparency/" class="art-card" data-category="smart">\n                        <div class="art-card-image art-card-image--smart">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></svg>\n                        </div>\n                        <div class="art-card-body">\n                            <span class="art-category-badge badge--smart">Smart Factory</span>\n                            <h3>จากรายงานกระดาษสู่ Production Transparency: คู่มือปฏิบัติ</h3>\n                            <p class="art-card-excerpt">การเดินทางจากรายงานกระดาษสู่การมองเห็นการผลิตแบบ Real-time ไม่ต้องลงทุนหลักล้าน นี่คือแนวทางปฏิบัติแบบเป็นขั้นตอน</p>\n                            <div class="art-card-footer">\n                                <span class="art-read-time">อ่าน 8 นาที</span>\n                                <span class="art-read-link">อ่านบทความ <span>&rarr;</span></span>\n                            </div>\n                        </div>\n                    </a>\n                </div>\n            </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Library"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Library: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Library: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="lib-section" data-particles>\n    <div class="dw-d-bg dw-d-bg--corner-tl" style="opacity: 0.06;"></div>\n            <div class="lib-inner" style="position: relative; z-index: 2;">\n                <div class="lib-header">\n                    <span class="blog-hub-label">คลังความรู้เจาะลึก</span>\n                    <h2>ความรู้เชิงโครงสร้างตามหัวข้อ</h2>\n                </div>\n\n                <div class="lib-groups">\n                    <div class="lib-group">\n                        <div class="lib-group-header">\n                            <div class="lib-group-indicator lib-group-indicator--boi"></div>\n                            <h3>BOI และการปฏิบัติตามกฎระเบียบ</h3>\n                        </div>\n                        <a href="/blog/boi-compliance-jin-hai/" class="lib-item">\n                            <span class="lib-item-title">โรงงานแห่งหนึ่งประหยัดภาษีเพิ่มเติม BOI ได้ 10 ล้านบาทต่อปี ได้อย่างไร</span>\n                            <div class="lib-item-meta">\n                                <span class="lib-item-time">8 นาที</span>\n                                <span class="lib-item-arrow">&rarr;</span>\n                            </div>\n                        </a>\n                    </div>\n\n                    <div class="lib-group">\n                        <div class="lib-group-header">\n                            <div class="lib-group-indicator lib-group-indicator--production"></div>\n                            <h3>การวางแผนการผลิต</h3>\n                        </div>\n                        <a href="/blog/lrp-vs-mrp/" class="lib-item">\n                            <span class="lib-item-title">LRP vs MRP: ทำไมการวางแผนการผลิตของคุณใช้เวลาหลายชั่วโมงแทนที่จะเป็นนาที</span>\n                            <div class="lib-item-meta">\n                                <span class="lib-item-time">6 นาที</span>\n                                <span class="lib-item-arrow">&rarr;</span>\n                            </div>\n                        </a>\n                        <a href="/blog/feature-codes/" class="lib-item">\n                            <span class="lib-item-title">Feature Codes: วิธีเปลี่ยน 27 SKU ให้เหลือ 1 ผลิตภัณฑ์</span>\n                            <div class="lib-item-meta">\n                                <span class="lib-item-time">6 นาที</span>\n                                <span class="lib-item-arrow">&rarr;</span>\n                            </div>\n                        </a>\n                        <a href="/blog/amrp-capacity-planning/" class="lib-item">\n                            <span class="lib-item-title">AMRP: ทำไมคุณไม่จำเป็นต้องมีระบบ APS แยกต่างหาก</span>\n                            <div class="lib-item-meta">\n                                <span class="lib-item-time">5 นาที</span>\n                                <span class="lib-item-arrow">&rarr;</span>\n                            </div>\n                        </a>\n                    </div>\n\n                    <div class="lib-group">\n                        <div class="lib-group-header">\n                            <div class="lib-group-indicator lib-group-indicator--cost"></div>\n                            <h3>การบริหารต้นทุน</h3>\n                        </div>\n                        <a href="/blog/co-product-cost-accounting/" class="lib-item">\n                            <span class="lib-item-title">การคิดต้นทุนผลิตภัณฑ์ร่วม: ปัญหาที่ ERP ส่วนใหญ่แก้ไม่ได้</span>\n                            <div class="lib-item-meta">\n                                <span class="lib-item-time">7 นาที</span>\n                                <span class="lib-item-arrow">&rarr;</span>\n                            </div>\n                        </a>\n                        <a href="/blog/dual-units/" class="lib-item">\n                            <span class="lib-item-title">หน่วยคู่: ทำไม ERP ของคุณควรแสดงทั้งกิโลกรัมและจำนวนชิ้น</span>\n                            <div class="lib-item-meta">\n                                <span class="lib-item-time">5 นาที</span>\n                                <span class="lib-item-arrow">&rarr;</span>\n                            </div>\n                        </a>\n                    </div>\n\n                    <div class="lib-group">\n                        <div class="lib-group-header">\n                            <div class="lib-group-indicator lib-group-indicator--smart"></div>\n                            <h3>Smart Factory</h3>\n                        </div>\n                        <a href="/blog/shop-floor-scheduling/" class="lib-item">\n                            <span class="lib-item-title">การจัดตารางย่อยหน้างาน: เมื่อแผนเจอความเป็นจริง</span>\n                            <div class="lib-item-meta">\n                                <span class="lib-item-time">5 นาที</span>\n                                <span class="lib-item-arrow">&rarr;</span>\n                            </div>\n                        </a>\n                        <a href="/blog/production-transparency/" class="lib-item">\n                            <span class="lib-item-title">จากรายงานกระดาษสู่ Production Transparency: คู่มือปฏิบัติ</span>\n                            <div class="lib-item-meta">\n                                <span class="lib-item-time">6 นาที</span>\n                                <span class="lib-item-arrow">&rarr;</span>\n                            </div>\n                        </a>\n                    </div>\n\n                    <div class="lib-group">\n                        <div class="lib-group-header">\n                            <div class="lib-group-indicator lib-group-indicator--industry"></div>\n                            <h3>ข้อมูลเชิงลึกอุตสาหกรรม</h3>\n                        </div>\n                        <a href="/blog/five-pain-points/" class="lib-item">\n                            <span class="lib-item-title">5 ปัญหาสากลที่เจ้าของโรงงานไทยทุกคนต้องเผชิญ</span>\n                            <div class="lib-item-meta">\n                                <span class="lib-item-time">5 นาที</span>\n                                <span class="lib-item-arrow">&rarr;</span>\n                            </div>\n                        </a>\n                        <a href="/blog/sap-ecc-end-of-life/" class="lib-item">\n                            <span class="lib-item-title">SAP ECC สิ้นสุดการสนับสนุน 2027: สิ่งที่ผู้ผลิตไทยต้องรู้</span>\n                            <div class="lib-item-meta">\n                                <span class="lib-item-time">5 นาที</span>\n                                <span class="lib-item-arrow">&rarr;</span>\n                            </div>\n                        </a>\n                    </div>\n                </div>\n            </div>\n    </div>\n    <script>/**\n * DigiWin 数据洋流 (Data Ocean Current)\n *\n * Recreates the brand kit\'s signature visual: a 3D dot-grid surface\n * with dramatic rolling wave crests, viewed from a low angle.\n * Reference: DigiWin 2025 Annual Report cover, brand kit pp.61-68.\n *\n * Usage:\n *   <section data-particles>              — subtle on light bg (default)\n *   <section data-particles="bold">       — vivid on dark navy bg\n *   <section data-particles="medium">     — moderate visibility\n *\n * WordPress: wp_enqueue_script or Code Module. Self-initializing.\n */\n\n(function () {\n    \'use strict\';\n\n    var reducedMotion = window.matchMedia(\'(prefers-reduced-motion: reduce)\').matches;\n    var PI2 = Math.PI * 2;\n\n    // ── Brand colors (RGB) ──────────────────────────────────────────\n    var BLUE = [0, 175, 240];   // #00AFF0 Smart Blue\n    var CYAN = [0, 230, 255];   // #00E6FF Cyan accent\n\n    // ── Presets ─────────────────────────────────────────────────────\n    var PRESETS = {\n        light: {\n            frontOpacity: 0.18,   // visible but not distracting on white/light backgrounds\n            backOpacity: 0.03,\n            frontRadius: 3.5,\n            backRadius: 0.5,\n            color: BLUE,\n            colorAlt: CYAN,\n            altRatio: 0.10\n        },\n        subtle: {\n            frontOpacity: 0.30,   // foreground dot opacity\n            backOpacity: 0.04,    // distant dot opacity\n            frontRadius: 4.5,     // foreground dot size (px)\n            backRadius: 0.6,      // distant dot size (px)\n            color: BLUE,\n            colorAlt: CYAN,\n            altRatio: 0.12\n        },\n        medium: {\n            frontOpacity: 0.45,\n            backOpacity: 0.06,\n            frontRadius: 5.0,\n            backRadius: 0.8,\n            color: BLUE,\n            colorAlt: CYAN,\n            altRatio: 0.18\n        },\n        bold: {\n            frontOpacity: 0.60,\n            backOpacity: 0.10,\n            frontRadius: 5.5,\n            backRadius: 1.0,\n            color: CYAN,\n            colorAlt: BLUE,\n            altRatio: 0.25\n        }\n    };\n\n    // ── Utility ─────────────────────────────────────────────────────\n    function lerp(a, b, t) { return a + (b - a) * t; }\n\n    // ── DataOcean class ─────────────────────────────────────────────\n    function DataOcean(el) {\n        this.el = el;\n        this.canvas = null;\n        this.ctx = null;\n        this.w = 0;\n        this.h = 0;\n        this.dpr = Math.min(window.devicePixelRatio || 1, 2);\n        this.visible = false;\n        this.raf = null;\n        this.time = 0;\n        this.resizeTimer = null;\n        this.colors = null; // pre-assigned per grid point\n\n        this.opts = this._parseOpts();\n        this._setup();\n        this._buildColors();\n        this._observe();\n\n        if (!reducedMotion) {\n            this._loop();\n        } else {\n            this.visible = true;\n            this._draw(0);\n        }\n    }\n\n    DataOcean.prototype._parseOpts = function () {\n        var name = this.el.getAttribute(\'data-particles\') || \'subtle\';\n        if (name === \'\' || name === \'true\') name = \'subtle\';\n        return PRESETS[name] || PRESETS.subtle;\n    };\n\n    DataOcean.prototype._setup = function () {\n        var c = document.createElement(\'canvas\');\n        c.setAttribute(\'aria-hidden\', \'true\');\n        c.style.cssText = \'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:0;\';\n        var pos = getComputedStyle(this.el).position;\n        if (pos === \'static\') this.el.style.position = \'relative\';\n        this.el.style.overflow = \'hidden\';\n        this.el.insertBefore(c, this.el.firstChild);\n        this.canvas = c;\n        this.ctx = c.getContext(\'2d\');\n        this._resize();\n\n        var self = this;\n        window.addEventListener(\'resize\', function () {\n            clearTimeout(self.resizeTimer);\n            self.resizeTimer = setTimeout(function () {\n                self._resize();\n                self._buildColors();\n            }, 200);\n        });\n    };\n\n    DataOcean.prototype._resize = function () {\n        var r = this.el.getBoundingClientRect();\n        this.w = r.width;\n        this.h = r.height;\n        this.canvas.width = this.w * this.dpr;\n        this.canvas.height = this.h * this.dpr;\n        this.ctx.setTransform(this.dpr, 0, 0, this.dpr, 0, 0);\n    };\n\n    // Grid: ~55 cols × ~35 rows. Pre-assign a color to each dot.\n    DataOcean.prototype._buildColors = function () {\n        var cols = Math.min(65, Math.ceil(this.w / 22) + 4);\n        var rows = 35;\n        this._cols = cols;\n        this._rows = rows;\n        var n = cols * rows;\n        this.colors = new Array(n);\n        var alt = this.opts.altRatio;\n        for (var i = 0; i < n; i++) {\n            this.colors[i] = Math.random() < alt ? this.opts.colorAlt : this.opts.color;\n        }\n    };\n\n    DataOcean.prototype._observe = function () {\n        var self = this;\n        if (\'IntersectionObserver\' in window) {\n            this._obs = new IntersectionObserver(function (e) {\n                self.visible = e[0].isIntersecting;\n            }, { rootMargin: \'150px 0px\' });\n            this._obs.observe(this.el);\n        } else {\n            this.visible = true;\n        }\n    };\n\n    DataOcean.prototype._loop = function () {\n        var self = this;\n        var last = 0;\n        (function tick(ts) {\n            self.raf = requestAnimationFrame(tick);\n            if (!self.visible) return;\n            if (ts - last < 30) return; // ~30 fps\n            last = ts;\n            self.time += 0.006;\n            self._draw(self.time);\n        })(0);\n    };\n\n    /**\n     * ── Core renderer ───────────────────────────────────────────────\n     *\n     * Approach: Think of a flat grid of dots on a table, viewed from a\n     * low angle. The table surface undulates with large rolling waves.\n     *\n     * "depth" goes from 0 (nearest / bottom of screen) to 1 (farthest /\n     * top area). Everything scales with depth:\n     *   - dot size shrinks\n     *   - dot opacity fades\n     *   - vertical row spacing compresses (perspective foreshortening)\n     *   - horizontal dot spacing tightens\n     *   - wave amplitude diminishes\n     *\n     * The wave function creates 2-3 visible rolling crests that sweep\n     * diagonally across the surface — matching the annual report cover.\n     */\n    DataOcean.prototype._draw = function (t) {\n        var ctx = this.ctx;\n        var w = this.w;\n        var h = this.h;\n        var opts = this.opts;\n        var cols = this._cols;\n        var rows = this._rows;\n\n        ctx.clearRect(0, 0, w, h);\n\n        // ── Perspective layout ──────────────────────────────────────\n        //\n        // The wave occupies the bottom ~55% of the section.\n        // "horizon" is where distant rows converge (top of wave area).\n        // "ground" is the bottom edge of the section.\n\n        var ground = h + 10;               // bottom edge (+ small overflow)\n        var horizon = h * 0.35;            // where distant dots vanish toward\n        var totalSpan = ground - horizon;   // vertical pixel range for the wave\n\n        var idx = 0;\n\n        // Draw back-to-front for correct visual layering\n        for (var row = rows - 1; row >= 0; row--) {\n\n            // ── Depth (0 = near/bottom, 1 = far/top) ───────────────\n            var depth = row / (rows - 1);\n\n            // Non-linear depth mapping: compress more toward horizon\n            // This creates the "accelerating compression" of perspective\n            var mappedDepth = Math.pow(depth, 0.55);\n\n            // Screen Y baseline for this row (no wave yet)\n            var baseY = ground - mappedDepth * totalSpan;\n\n            // ── Per-row properties (lerp by depth) ──────────────────\n            var dotR = lerp(opts.frontRadius, opts.backRadius, depth);\n            var dotA = lerp(opts.frontOpacity, opts.backOpacity, depth);\n            var colSpacing = lerp(w / (cols - 4), w / (cols + 15), depth);\n\n            // Slight horizontal offset per row (creates diagonal sweep)\n            var rowShift = depth * w * 0.12;\n\n            // ── Wave: two layers for organic rolling feel ───────────\n            //\n            // Primary wave: large rolling crests (creates the signature look)\n            // Secondary wave: smaller ripple for naturalism\n            //\n            // Wave amplitude is BIG near foreground and diminishes with depth.\n            // This is what makes the crests dramatically visible.\n\n            var waveScale = (1 - depth * 0.75); // waves diminish into distance\n            var amp1 = 70 * waveScale;           // primary crest amplitude (px)\n            var amp2 = 25 * waveScale;           // secondary ripple\n\n            for (var col = 0; col < cols; col++) {\n                // Screen X\n                var screenX = col * colSpacing - rowShift + colSpacing * 0.5;\n\n                // Wrap X for seamless edge handling\n                if (screenX < -30 || screenX > w + 30) { idx++; continue; }\n\n                // ── Wave displacement ───────────────────────────────\n                //\n                // The primary wave sweeps diagonally (uses both col and row).\n                // freq values tuned so ~2 full crests are visible across width.\n\n                var worldX = col * 24; // stable world-space coordinate for wave\n                var worldZ = row * 18;\n\n                var wave = amp1 * Math.sin(\n                    worldX * 0.0065 + worldZ * 0.012 + t * 0.9\n                );\n                wave += amp2 * Math.sin(\n                    worldX * 0.013 - worldZ * 0.008 + t * 0.55 + 1.8\n                );\n\n                var screenY = baseY - wave;\n\n                // Skip if outside visible area\n                if (screenY < -15 || screenY > h + 15) { idx++; continue; }\n\n                // ── Draw dot ────────────────────────────────────────\n                var c = this.colors[idx % this.colors.length];\n                ctx.beginPath();\n                ctx.arc(screenX, screenY, dotR, 0, PI2);\n                ctx.fillStyle = \'rgba(\' + c[0] + \',\' + c[1] + \',\' + c[2] + \',\' + dotA + \')\';\n                ctx.fill();\n\n                idx++;\n            }\n        }\n    };\n\n    DataOcean.prototype.destroy = function () {\n        if (this.raf) cancelAnimationFrame(this.raf);\n        if (this._obs) this._obs.disconnect();\n        if (this.canvas && this.canvas.parentNode) {\n            this.canvas.parentNode.removeChild(this.canvas);\n        }\n    };\n\n    // ── Auto-init ───────────────────────────────────────────────────\n    function init() {\n        var els = document.querySelectorAll(\'[data-particles]\');\n        var inst = [];\n        for (var i = 0; i < els.length; i++) inst.push(new DataOcean(els[i]));\n\n        window.DigiWinParticleOcean = {\n            instances: inst,\n            DataOcean: DataOcean,\n            refresh: function () {\n                for (var j = 0; j < inst.length; j++) inst[j].destroy();\n                inst = [];\n                var els2 = document.querySelectorAll(\'[data-particles]\');\n                for (var k = 0; k < els2.length; k++) inst.push(new DataOcean(els2[k]));\n                this.instances = inst;\n            }\n        };\n    }\n\n    if (document.readyState === \'loading\') {\n        document.addEventListener(\'DOMContentLoaded\', init);\n    } else {\n        init();\n    }\n})();\n</script><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hub Cta"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hub Cta: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hub Cta: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="dw-d-bg dw-d-bg--left" style="opacity: 0.10;"></div>\n\n            <div class="dw-wave-flow" style="height: 140px; opacity: 0.25; z-index: 1;"></div>\n            <div class="hubc-cta-inner" style="position: relative; z-index: 2;">\n                <h2>มีความท้าทายด้านการผลิต?</h2>\n                <p>ทีมงานของเราช่วยโรงงานไทยกว่า 100 แห่งแก้ปัญหาด้านการผลิต การปฏิบัติตามกฎระเบียบ และต้นทุน พูดคุยกับเราเรื่องของคุณ</p>\n                <div class="hubc-cta-buttons">\n                    <a href="/demo/" class="hubc-btn-white">พูดคุยกับเรา</a>\n                    <a href="/products/" class="hubc-btn-outline">ดูผลิตภัณฑ์</a>\n                </div>\n            </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100788;

