INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100788, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === HUB HERO (S1) === */\n/* Divi 5 section boilerplate (font-smoothing, p padding, heading resets) */\n.hubh-section{position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.hubh-section p{padding-bottom:0;line-height:1.6}\n.hubh-section h2,.hubh-section h3,.hubh-section h4{margin:0;padding:0;line-height:1.6}\n\n\n/* === PSEUDO-ELEMENTS (auto-ported from styles.css) === */\n.hubh-hub-hero::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Ccircle cx=\'30\' cy=\'30\' r=\'1.5\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");pointer-events:none}\n.hubh-hub-hero::after{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background:radial-gradient(ellipse at 70% 30%, rgba(0, 175, 240, 0.12) 0%, transparent 50%),radial-gradient(ellipse at 30% 80%, rgba(0, 175, 240, 0.08) 0%, transparent 40%);pointer-events:none}\n.hubh-hero-badge::before{content:\'\';width:8px;height:8px;background:#00AFF0;border-radius:50%;animation:pulse-dot 2s ease-in-out infinite}\n/* REF: BASE RULES from styles.css (check against inline CSS above) */\n/* .dw-d-bg{position:absolute;right:-10%;top:50%;transform:translateY(-50%);width:60%;min-height:60vh;background:url(\'assets/digiwin-d-outline.svg\') no-repeat center right;background-size:contain;pointer-events:none;z-index:0;opacity:0.12} */\n/* .dw-d-bg--gradient{background-image:url(\'assets/digiwin-d-gradient.svg\');opacity:0.15} */\n/* .dw-d-bg--particle{background-image:url(\'assets/digiwin-d-particle.svg\');opacity:0.2} */\n/* .dw-d-bg--left{right:auto;left:-15%;background-position:center left} */\n/* .dw-d-bg--bottom{top:auto;bottom:-20%;transform:none;background-position:center bottom} */\n/* .dw-d-bg--top{top:-20%;transform:none;background-position:center top} */\n/* .dw-d-bg--center{right:auto;left:50%;transform:translate(-50%, -50%);width:80%;min-height:80vh;background-position:center center} */\n/* .dw-d-bg--corner{width:30%;min-height:30vh} */\n/* .dw-d-bg--corner-tl{right:auto;left:-5%;top:-5%;transform:none} */\n/* .dw-d-bg--corner-br{top:auto;bottom:-5%;right:-5%;transform:none} */\n/* .dw-d-bg--bold{opacity:0.22 !important} */\n/* .dw-d-bg--medium{opacity:0.14 !important} */\n/* .dw-d-bg--subtle{opacity:0.06 !important} */\n/* .blog-hero-inner{max-width:800px;margin:0 auto;position:relative;z-index:1} */\n/* .blog-hub-hero{background:linear-gradient(135deg, #000432 0%, #000864 50%, #001080 100%);padding:160px 0 100px;position:relative;overflow:hidden;text-align:center} */\n/* .blog-hero-illustration{position:absolute;bottom:0;right:0;width:600px;height:100%;z-index:1;overflow:hidden} */\n/* .blog-hero-illustration svg{position:absolute;bottom:-40px;right:-20px;width:560px;height:480px;opacity:0.12} */\n/* .blog-hero-inner{max-width:1200px;margin:0 auto;padding:0 24px;position:relative;z-index:2;animation:slide-up 0.8s ease-out} */\n/* .blog-hero-badge{display:inline-flex;align-items:center;gap:10px;background:rgba(0, 175, 240, 0.1);border:1px solid rgba(0, 175, 240, 0.3);padding:10px 20px;border-radius:50px;color:#00AFF0;font-family:\'JetBrains Mono\', monospace;font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;margin-bottom:28px} */\n/* .blog-hub-hero h1{font-family:\'Noto Sans\', sans-serif;font-size:clamp(40px, 5vw, 56px);font-weight:700;color:#fff;margin:0 0 24px 0;line-height:1.1;letter-spacing:-0.03em} */\n/* .blog-hero-subtitle{font-family:\'Noto Sans\', sans-serif;font-size:20px;color:rgba(255, 255, 255, 0.8);line-height:1.6;max-width:640px;margin:0 auto 48px} */\n/* .blog-hero-stats{display:flex;justify-content:center;gap:48px} */\n/* .blog-hero-stat{text-align:center} */\n/* .blog-hero-stat-number{font-family:\'Noto Sans\', sans-serif;font-size:28px;font-weight:700;color:#00AFF0;margin-bottom:4px} */\n/* .blog-hero-stat-label{font-family:\'Noto Sans\', sans-serif;font-size:14px;color:rgba(255, 255, 255, 0.85)} */\n/* @media (max-width:1024px){.blog-hero-illustration{width:400px;opacity:0.7}} */\n/* @media (max-width:640px){.blog-hero-illustration{display:none}.blog-hub-hero{padding:120px 0 80px}.blog-hub-hero h1{font-size:32px}.blog-hero-subtitle{font-size:17px}.blog-hero-stats{flex-direction:column;gap:20px}} */\n.dw-d-bg{position:absolute;top:-20%;right:-10%;bottom:auto;left:auto;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center top;background-size:contain;opacity:0.15;pointer-events:none;z-index:0}\n\n\n\n/* Divi section-level overrides */\n.et_pb_section:has(.hubh-hero-inner) {\n  background: linear-gradient(135deg, #000432 0%, #000864 50%, #001080 100%) !important;\n  padding: 160px 24px 100px !important;\n  position: relative !important;\n  overflow: hidden !important;\n  text-align: center !important;\n  min-height: auto !important;\n  margin-top: 0 !important; margin-bottom: 0 !important;\n}\n.et_pb_section:has(.hubh-hero-inner)::before {\n  content: \'\' !important;\n  position: absolute !important;\n  inset: 0 !important;\n  background-image: url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Ccircle cx=\'30\' cy=\'30\' r=\'1.5\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E") !important;\n  pointer-events: none !important;\n}\n.et_pb_section:has(.hubh-hero-inner)::after {\n  content: \'\' !important;\n  position: absolute !important;\n  inset: 0 !important;\n  background: radial-gradient(ellipse at 70% 30%, rgba(0,175,240,0.12) 0%, transparent 50%), radial-gradient(ellipse at 30% 80%, rgba(0,175,240,0.08) 0%, transparent 40%) !important;\n  pointer-events: none !important;\n}\n.et_pb_section:has(.hubh-hero-inner) .et_pb_row {\n  max-width: 100% !important; width: 100% !important; padding: 0 !important; margin: 0 auto !important;\n}\n.et_pb_section:has(.hubh-hero-inner) .et_pb_column { padding: 0 !important; }\n.et_pb_section .hubh-hero-inner {\n  max-width: 1200px !important; margin: 0 auto !important; padding: 0 24px !important;\n  position: relative !important; z-index: 2 !important; text-align: center !important;\n  -webkit-font-smoothing: auto !important;\n}\n.et_pb_section .hubh-hero-badge {\n  display: inline-flex !important; align-items: center !important; gap: 10px !important;\n  background: rgba(0,175,240,0.1) !important; border: 1px solid rgba(0,175,240,0.3) !important;\n  padding: 10px 20px !important; border-radius: 50px !important; color: #00AFF0 !important;\n  font-family: \'JetBrains Mono\', monospace !important; font-size: 11px !important;\n  font-weight: 500 !important; text-transform: uppercase !important; letter-spacing: 0.1em !important;\n  margin-bottom: 28px !important; line-height: 17.6px !important;\n  -webkit-font-smoothing: auto !important;\n}\n.et_pb_section .hubh-hero-inner h1 {\n  font-family: \'Noto Sans\', sans-serif !important; font-size: 56px !important;\n  font-weight: 700 !imp