\n#bf-all:checked ~ .blog-hub-filter-tabs label[for="bf-all"],\n#bf-boi:checked ~ .blog-hub-filter-tabs label[for="bf-boi"],\n#bf-production:checked ~ .blog-hub-filter-tabs label[for="bf-production"],\n#bf-cost:checked ~ .blog-hub-filter-tabs label[for="bf-cost"],\n#bf-smart:checked ~ .blog-hub-filter-tabs label[for="bf-smart"],\n#bf-industry:checked ~ .blog-hub-filter-tabs label[for="bf-industry"] {\n  background: #006dac !important; color: #fff !important;\n  box-shadow: 0 2px 8px rgba(0,175,240,0.3) !important;\n}\n/* CSS-only filter: hide non-matching cards */\n#bf-boi:checked ~ .articles-grid .art-card:not([data-category="boi"]),\n#bf-production:checked ~ .articles-grid .art-card:not([data-category="production"]),\n#bf-cost:checked ~ .articles-grid .art-card:not([data-category="cost"]),\n#bf-smart:checked ~ .articles-grid .art-card:not([data-category="smart"]),\n#bf-industry:checked ~ .articles-grid .art-card:not([data-category="industry"]) {\n  display: none !important;\n}\n.et_pb_section .articles-grid {\n  display: grid !important; grid-template-columns: repeat(3, 1fr) !important; gap: 32px !important;\n}\n.et_pb_section .art-card {\n  background: #fff !important; border-radius: 16px !important; overflow: hidden !important;\n  border: 1px solid #e8eef3 !important; box-shadow: 0 2px 12px rgba(0,0,0,0.04) !important;\n  text-decoration: none !important; display: flex !important; flex-direction: column !important;\n  line-height: 25.6px !important; -webkit-font-smoothing: auto !important;\n  color: #333 !important; text-align: start !important;\n}\n.et_pb_section .art-card-image {\n  height: 180px !important; display: flex !important; align-items: center !important;\n  justify-content: center !important; position: relative !important; overflow: hidden !important;\n}\n.et_pb_section .art-card-image svg {\n  width: 56px !important; height: 56px !important; stroke-width: 1.5 !important;\n  fill: none !important; opacity: 0.5 !important;\n}\n.et_pb_section .art-card-image--boi { background: linear-gradient(135deg, #7f1d1d 0%, #991b1b 50%, #b91c1c 100%) !important; }\n.et_pb_section .art-card-image--boi svg { stroke: #fca5a5 !important; }\n.et_pb_section .art-card-image--production { background: linear-gradient(135deg, #1e3a5f 0%, #1e4a7a 50%, #2563a0 100%) !important; }\n.et_pb_section .art-card-image--production svg { stroke: #93c5fd !important; }\n.et_pb_section .art-card-image--cost { background: linear-gradient(135deg, #064e3b 0%, #065f46 50%, #047857 100%) !important; }\n.et_pb_section .art-card-image--cost svg { stroke: #6ee7b7 !important; }\n.et_pb_section .art-card-image--smart { background: linear-gradient(135deg, #3b0764 0%, #4c1d95 50%, #5b21b6 100%) !important; }\n.et_pb_section .art-card-image--smart svg { stroke: #c4b5fd !important; }\n.et_pb_section .art-card-image--industry { background: linear-gradient(135deg, #78350f 0%, #92400e 50%, #a16207 100%) !important; }\n.et_pb_section .art-card-image--industry svg { stroke: #fcd34d !important; }\n.et_pb_section .art-card-body {\n  padding: 24px !important; flex: 1 !important; display: flex !important;\n  flex-direction: column !important;\n}\n.et_pb_section .art-category-badge {\n  font-family: \'JetBrains Mono\', monospace !important; font-size: 10px !important;\n  font-weight: 500 !important; text-transform: uppercase !important; letter-spacing: 0.1em !important;\n  padding: 4px 10px !important; border-radius: 4px !important; display: inline-block !important;\n  width: fit-content !important; margin-bottom: 12px !important; line-height: 16px !important;\n  -webkit-font-smoothing: auto !important;\n}\n.et_pb_section .badge--boi { background: rgba(220,38,38,0.1) !important; color: #b91c1c !important; }\n.et_pb_section .badge--production { background: rgba(0,175,240,0.1) !important; color: #0369a1 !important; }\n.et_pb_section .badge--cost { background: rgba(5,150,105,0.1) !important; color: #047857 !important; }\n.et_pb_section .badge--smart { background: rgba(124,5